import React, { useState } from 'react';
import './Login.css';

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    // Simulate login process
    setTimeout(() => {
      setIsLoading(false);
      // Handle login logic here
      console.log('Login attempt:', { email, password });
    }, 1500);
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <div className="logo-section">
            <h1 className="login-title">
              Login to <span className="logo-text">Mello<span className="logo-highlight">minds</span></span>
            </h1>
          </div>
          <p className="welcome-text">
            Welcome back! <span className="subtitle">Please login to continue</span>
          </p>
        </div>

        <form className="login-form" onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="email" className="form-label">Email</label>
            <div className="input-container">
              <img 
                src="/Light-Icon/Iconly/Light-Outline/Profile.svg" 
                alt="Email" 
                className="input-icon"
              />
              <input
                type="email"
                id="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="enter email address"
                className="form-input"
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label htmlFor="password" className="form-label">Password</label>
            <div className="input-container">
              <img 
                src="/Light-Icon/Iconly/Light-Outline/Lock.svg" 
                alt="Password" 
                className="input-icon"
              />
              <input
                type={showPassword ? 'text' : 'password'}
                id="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="enter password"
                className="form-input"
                required
              />
              <button
                type="button"
                className="password-toggle"
                onClick={togglePasswordVisibility}
              >
                <img 
                  src={showPassword ? "/Light-Icon/Iconly/Light-Outline/Hide.svg" : "/Light-Icon/Iconly/Light-Outline/Show.svg"}
                  alt={showPassword ? "Hide password" : "Show password"}
                  className="toggle-icon"
                />
              </button>
            </div>
          </div>

          <div className="forgot-password">
            <button type="button" className="forgot-link">
              Forgot Your Password?
            </button>
          </div>

          <button 
            type="submit" 
            className={`login-button ${isLoading ? 'loading' : ''}`}
            disabled={isLoading}
          >
            {isLoading ? 'Logging in...' : 'Login'}
          </button>
        </form>
      </div>

      <div className="mascot-container">
        <div className="mascot">
          <div className="mascot-face">
            <div className="mascot-eye left-eye"></div>
            <div className="mascot-eye right-eye"></div>
          </div>
        </div>
      </div>

      <footer className="login-footer">
        <p>All Rights Reserved. 2026 MelloMinds LLP</p>
      </footer>
    </div>
  );
};

export default Login;
